export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "七點半。食堂。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言端著餐盤，站在取餐窗口旁邊的柱子後面。他沒有急著坐下。他在看。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一件事。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "隊伍裡，一個穿反光背心的志工正在翻自己的背包，動作越來越大，最後把背包整個倒過來抖了抖。幾本課本和一枝筆掉出來，但他在找的顯然不是這些。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Student, character: "學生", dialogue: "我雨衣呢？明明昨晚掛在椅子上的——誰拿了？", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)和上一輪一樣。同一個人，同一句話，同一個時間。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的嘴唇動了一下，把那個人的下一句話無聲地念了出來——", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Student, character: "學生", dialogue: "算了算了，反正今天有的是雨衣。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一字不差。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一件，對了。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉向取餐窗口。早餐分四個區，最右邊那個窗口排的隊最長——肉鬆麵包。他記得上一輪這個窗口的肉鬆麵包在七點三十五分的時候發完，排在後面的人只能改買紅豆的。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第二件事。肉鬆麵包。七點三十五分。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看了一眼牆上的鐘。07:33。窗口裡的阿姨正在往盤子裡夾最後兩個。隊伍裡還有四個人。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:34。第三個人拿走了倒數第二個。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:35。第四個人伸手——", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗口裡傳出來一句話——肉鬆的沒了，換紅豆的。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第二件，也對了。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩件事。兩個精確到分鐘的預測。沒有任何模糊的餘地——不是「差不多那個時候」，是恰好那個時間，恰好那句話，恰好那個結果。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是幻覺。不是夢。這一天在重播。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他端著餐盤找了個角落的位置坐下。紅豆麵包，溫豆漿。和上一輪一樣的選擇，因為上一輪他排到窗口的時候肉鬆的也剛好賣完了。他咬了一口麵包。味道一樣。豆漿的溫度一樣。連紙杯上印的校慶 Logo 偏了一毫米的角度都一樣。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第三件事。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他抬起頭，看向食堂門口。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:40。門口會有一個人衝進來。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他等著。嚼麵包。數秒。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門被推開了。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個女生——紮馬尾，胸前掛著藍色工作證，兩手各抱著一捲大海報——幾乎是撞進來的。她的步伐太快，海報的紙筒太長，進門的時候紙筒的尾端掃到了門框邊的飲料台。飲料台上擺著一排剛補充的紙杯豆漿和奶茶——", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "上一輪，她的海報掃到了最外面那排紙杯。三杯豆漿翻倒，潑了半個飲料台。奶茶濺到了旁邊排隊的人。有人罵了一句。女生嚇得臉都白了，海報掉了一捲，場面混亂了三分鐘。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但這一次——", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站起來了。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "動作不快，甚至可以說很隨意，像一個吃完早餐準備離開的學生順手做了一件小事。他端著餐盤走到飲料台旁邊，把餐盤放在台面上，然後伸手——", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在女生的海報紙筒掃到第一杯豆漿之前，他用手肘把那排紙杯往裡推了五公分。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "紙筒從紙杯邊緣擦過去。差了不到兩公分。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有翻倒。沒有潑濺。沒有人罵。沒有人混亂。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "女生抱著海報衝過去了，什麼都沒注意到。飲料台上的紙杯們安安靜靜地站著，像一排什麼事都沒發生過的士兵。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯成了。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看著那排紙杯。看了一秒，兩秒，三秒。食堂裡的喧嘩聲繼續著。有人在排隊，有人在吃飯，有人在喊朋友佔位子。廣播在天花板上念著什麼，聲音被嘈雜蓋住了大半。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)世界沒有崩。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)上一輪在這裡翻了三杯豆漿。這一輪一杯都沒翻。事情被我改了。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)周圍的人沒有感覺。廣播沒有中斷。沒有什麼東西跳出來說「你改了不該改的」。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這不是只能重看一遍的錄影帶。我能改東西。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這個想法太輕了。輕到他在心裡說完之後自己都不太敢信。但那排沒翻倒的紙杯就在他面前，實實在在地站著，像一個不需要語言的證明。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "廣播的聲音從嘈雜裡浮上來，清晰了幾秒。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Announcement, character: "廣播", dialogue: "⋯⋯百年時間膠囊展示將於下午兩點在校史館一樓大廳正式揭幕，屆時請各班有序參觀——", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第四件事。百年時間膠囊展示。下午兩點。和上一輪一樣。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "四件事。三件原封不動地發生了。一件被他改變了。世界在重播，但不是每一幀都被鎖死——有些地方，他可以插手。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果能改一杯豆漿翻不翻——", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果我能改一個人走不走那條路——", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那我是不是也能改——", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有把那個詞想完。但他知道是什麼。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)死亡。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)上一輪我去了鐘樓。這一輪我不去。上一輪我告訴了邵叔。這一輪我不告訴。上一輪我留在學校。這一輪我離開。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)三個變量。三個我能改的東西。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這不再只是惡夢了。這是一張地圖。我走過一次了，知道哪裡是死路。這一次，我換一條路走。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拿起餐盤，走到回收台，把紙杯和紙袋倒進垃圾桶。動作平穩。他的臉和進食堂的時候沒有任何區別——同一張沒什麼表情的臉，同一雙半闔的眼睛，同一個微微佝僂的身影。但如果有人仔細看——沒有人會仔細看——他會發現這個少年的脊背比進來的時候直了一點點。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走出食堂。雨還在下，比早上大了一點。風從海面上斜斜地刮過來，把校慶旗幟吹得啪啪響。主道上全是人——穿反光背心的志工、扛器材的工作人員、打著傘的外賓。所有人都在往同一個方向走，像被同一條河流推著。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他們在走他們的劇本。每一個人都在走上一輪走過的路。說同樣的話，做同樣的事。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)只有我不一樣。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)只有我記得上一次。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在食堂門口的台階上，看著面前的人群和雨幕。遠處，鐘樓的灰色輪廓在雨霧裡若隱若現，指針在走，不緊不慢，像一個不需要趕路的老人。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)今晚十點二十二分，你會停電。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但我不會在那裡。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他邁下台階，走進雨裡。腳步比來的時候快了一點。不是跑，是一種有方向的走——像一個終於知道自己要去哪裡的人。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)先找到出口。趁天還沒黑，趁路還沒封，離開這座學校。", background: Background.Chapter_2_Ch2_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "八點。雨勢不減。校慶的人群在主道上湧動，歡笑、抱怨、寒暄、拍照。廣播的女聲在天花板上循環播放著同一段百年校慶提醒。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有人知道，一個十七歲的少年剛剛在食堂裡用一杯豆漿做了一個實驗。也沒有人知道，那個實驗的結果正在改變他今天接下來每一步的方向。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他朝校門的方向走去。", background: Background.Chapter_2_Ch2_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "口袋裡的手機安靜地躺著。那條訊息還在裡面，像一顆埋在土裡的種子，等著天黑。", background: Background.Chapter_2_Ch2_Act3_S0 },
];
